#!/usr/bin/env node
/**
 * CI Bundle Budget Enforcement
 *
 * Parses .next/diagnostics/route-bundle-stats.json (generated by `next build`)
 * and checks that every page's first-load JS stays within the budget.
 *
 * Next.js "first-load JS" includes the shared framework bundle (React, Next.js
 * runtime, layout components) which is ~1.3 MB uncompressed.  The budget here
 * applies to the TOTAL first-load JS per page.  A sensible default for a
 * feature-rich Next.js 16 app with Radix UI, Stripe, Supabase, Framer Motion,
 * etc. is ~1700 KB uncompressed (~350 KB gzipped).
 *
 * Override with BUNDLE_BUDGET_KB env var.
 * Sanity Studio routes (/studio) are excluded — they are internal-only.
 */

import { readFileSync } from "node:fs";
import { join } from "node:path";

const BUDGET_KB = Number(process.env.BUNDLE_BUDGET_KB ?? 1700);
const BUDGET_BYTES = BUDGET_KB * 1024;
const STATS_PATH = join(process.cwd(), ".next", "diagnostics", "route-bundle-stats.json");

// ── helpers ──────────────────────────────────────────────────────────────────

function formatKB(bytes) {
  return `${(bytes / 1024).toFixed(1)} KB`;
}

// ── main ─────────────────────────────────────────────────────────────────────

let stats;
try {
  stats = JSON.parse(readFileSync(STATS_PATH, "utf-8"));
} catch {
  console.error(`❌  Could not read ${STATS_PATH}`);
  console.error("    Run `pnpm build` first to generate route bundle stats.");
  process.exit(1);
}

if (!Array.isArray(stats) || stats.length === 0) {
  console.error("❌  route-bundle-stats.json is empty or malformed.");
  process.exit(1);
}

// Exclude internal / non-page routes
const EXCLUDED_PREFIXES = ["/studio", "/api/", "/_"];

const pages = stats.filter(
  (entry) => !EXCLUDED_PREFIXES.some((prefix) => entry.route.startsWith(prefix))
);

const violations = [];
const passing = [];

for (const page of pages) {
  const size = page.firstLoadUncompressedJsBytes ?? 0;
  const entry = { route: page.route, size };

  if (size > BUDGET_BYTES) {
    violations.push(entry);
  } else {
    passing.push(entry);
  }
}

// ── report ───────────────────────────────────────────────────────────────────

console.log(`\n📦  Bundle Budget Check  (limit: ${BUDGET_KB} KB per page)\n`);
console.log(`   Pages checked: ${pages.length}`);
console.log(`   Passing:       ${passing.length}`);
console.log(`   Over budget:   ${violations.length}\n`);

if (passing.length > 0) {
  console.log("✅  Passing routes:");
  for (const p of passing.toSorted((a, b) => b.size - a.size)) {
    const pct = ((p.size / BUDGET_BYTES) * 100).toFixed(0);
    console.log(`     ${formatKB(p.size).padStart(10)}  (${pct.padStart(3)}%)  ${p.route}`);
  }
  console.log();
}

if (violations.length > 0) {
  console.log("❌  Over-budget routes:");
  for (const v of violations.toSorted((a, b) => b.size - a.size)) {
    const over = formatKB(v.size - BUDGET_BYTES);
    console.log(`     ${formatKB(v.size).padStart(10)}  (+${over})  ${v.route}`);
  }
  console.log();
  console.log(
    `💡  Reduce JS by lazy-loading heavy components, splitting routes, or\n` +
    `    removing unused dependencies.  Re-run with BUNDLE_BUDGET_KB=<n> to\n` +
    `    adjust the threshold.\n`
  );
  process.exit(1);
}

console.log("🎉  All pages are within the bundle budget!\n");
